-- =============================================================================
-- Seed de desenvolvimento local
-- Este arquivo existe para popular o Supabase local com dados previsiveis.
-- Nunca use este seed em staging ou producao.
-- =============================================================================

BEGIN;

-- ---------------------------------------------------------------------------
-- 1. Observacao sobre autenticacao local
-- ---------------------------------------------------------------------------
-- O usuario admin local e criado separadamente por scripts/seed-auth-local.sh.
-- Isso evita que mudancas internas do schema auth quebrem o `supabase start`.

-- ---------------------------------------------------------------------------
-- 2. Campeonato base
-- ---------------------------------------------------------------------------
INSERT INTO public.championships (
  id,
  name,
  season,
  status,
  points_win,
  points_draw,
  points_loss,
  periods_count,
  period_duration,
  created_at
)
VALUES (
  '10000000-0000-0000-0000-000000000001',
  'Copa Local de Desenvolvimento',
  '2026',
  'active',
  3,
  1,
  0,
  2,
  7,
  now()
)
ON CONFLICT (id) DO UPDATE
SET
  name = EXCLUDED.name,
  season = EXCLUDED.season,
  status = EXCLUDED.status,
  points_win = EXCLUDED.points_win,
  points_draw = EXCLUDED.points_draw,
  points_loss = EXCLUDED.points_loss,
  periods_count = EXCLUDED.periods_count,
  period_duration = EXCLUDED.period_duration;

