INSERT INTO public.players (
  id,
  name,
  preferred_position,
  official_name,
  email,
  created_at
)
SELECT
  player_id::uuid,
  name,
  preferred_position,
  name,
  lower(replace(name, ' ', '.')) || '@players.local.test',
  now()
FROM player_seed
ON CONFLICT (id) DO UPDATE
SET
  name = EXCLUDED.name,
  preferred_position = EXCLUDED.preferred_position,
  official_name = EXCLUDED.official_name,
  email = EXCLUDED.email;

